pragma solidity ^0.8.0;

contract PuzzleReward {
    bytes32 public puzzle;
    uint256 public reward;
    address public owner;

    constructor(bytes32 _puzzle) payable {
        puzzle = _puzzle;
        reward = msg.value;
        owner = msg.sender;
    }

    function claimReward(bytes32 solution) public {
        require(keccak256(abi.encodePacked(solution)) == puzzle, "Wrong answer");
        payable(msg.sender).transfer(reward);
        reward = 0;
    }
}

