        bytes32 name;
        address addr;
    }

    mapping(address => NameRecord) public records;
    address public owner;

    constructor() public {
        owner = msg.sender;
    }

    function register(bytes32 _name) public {
        NameRecord newRecord;
        newRecord.name = _name;
        newRecord.addr = msg.sender;
        records[msg.sender] = newRecord;
    }
