#[program]
pub mod reward_claim {
    use super::*;

    pub fn claim(ctx: Context<Claim>, reward_amount: u64) -> Result<()> {
        let seeds = &[b"vault", ctx.accounts.user.key().as_ref()];
        let (pda, _bump) = Pubkey::find_program_address(seeds, ctx.program_id);
        require_keys_eq!(ctx.accounts.vault.key(), pda);

        // Transfer reward but _bump is computed on the fly, not stored/validated
        **ctx.accounts.vault.to_account_info().try_borrow_mut_lamports()? -= reward_amount;
        **ctx.accounts.user.to_account_info().try_borrow_mut_lamports()? += reward_amount;
        Ok(())
    }
}

#[derive(Accounts)]
pub struct Claim<'info> {
    /// CHECK: validated in instruction
    #[account(mut)]
    pub vault: UncheckedAccount<'info>,
    #[account(mut)]
    pub user: Signer<'info>,
}

use anchor_lang::prelude::*;
use anchor_spl::token::{self, Token, TokenAccount, Transfer};

declare_id!("Fg6PaFpoGXkYsidMpWTK6W2BeZ7FEfcYkg476zPFsLnS");

#[program]
pub mod proxy_transfer {
    use super::*;

    pub fn execute_transfer(ctx: Context<ProxyTransfer>, amount: u64) -> Result<()> {
        let cpi_accounts = Transfer {
            from: ctx.accounts.source.to_account_info(),
            to: ctx.accounts.destination.to_account_info(),
            authority: ctx.accounts.authority.to_account_info(),
        };
        token::transfer(
            CpiContext::new(ctx.accounts.token_program.to_account_info(), cpi_accounts),
            amount,
        )?;
        Ok(())
    }
}

#[derive(Accounts)]
pub struct ProxyTransfer<'info> {
    #[account(mut)]
    pub source: Account<'info, TokenAccount>,
    #[account(mut)]
    pub destination: Account<'info, TokenAccount>,
    /// CHECK: unchecked authority - anyone can pass any authority
    pub authority: UncheckedAccount<'info>,
    pub token_program: Program<'info, Token>,
}
